import React, { useState } from 'react';
import { generateServerFiles, type GatewayConfig, type ProtocolConfig } from '../../utils/gatewayGenerator';

const defaultConfig: GatewayConfig = {
  name: 'Industrial Gateway',
  version: '1.0.0',
  description: 'Industrial Protocol Gateway Server',
  server: {
    host: '0.0.0.0',
    port: 8080,
    ssl: false,
    authentication: false
  },
  protocols: [
    {
      id: 'modbus-1',
      name: 'Modbus TCP Gateway',
      type: 'modbus-tcp' as const,
      enabled: true,
      mode: 'server' as const,
      settings: {
        serverPort: 502,
        unitId: 1,
        registerMap: {
          holdingRegisters: { start: 40001, count: 100 },
          inputRegisters: { start: 30001, count: 50 }
        }
      }
    }
  ],
  logging: {
    level: 'info',
    file: false,
    console: true
  }
};

const protocolTypes = [
  { value: 'modbus-tcp', label: 'Modbus TCP' },
  { value: 'modbus-rtu', label: 'Modbus RTU' },
  { value: 'opcua', label: 'OPC UA' },
  { value: 'mqtt', label: 'MQTT' },
  { value: 'profinet', label: 'PROFINET' },
  { value: 'ethernet-ip', label: 'EtherNet/IP' },
  { value: 'bacnet', label: 'BACnet' },
  { value: 'dnp3', label: 'DNP3' },
  { value: 'iec-61850', label: 'IEC 61850' }
];

const GatewayBuilder: React.FC = () => {
  const [config, setConfig] = useState<GatewayConfig>(defaultConfig);
  const [isGenerating, setIsGenerating] = useState(false);
  const [activeProtocolTab, setActiveProtocolTab] = useState<string>('http-api');

  const updateConfig = (field: keyof GatewayConfig, value: any) => {
    setConfig(prev => ({ ...prev, [field]: value }));
  };

  const addProtocol = () => {
    const newProtocolId = `protocol-${Date.now()}`;
    const newProtocol: ProtocolConfig = {
      id: newProtocolId,
      name: 'New Protocol',
      type: 'modbus-tcp' as const,
      enabled: true,
      mode: 'server' as const,
      settings: getDefaultProtocolSettings('modbus-tcp', 'server')
    };
    
    setConfig(prev => ({
      ...prev,
      protocols: [...prev.protocols, newProtocol]
    }));
    
    // Switch to the new protocol tab
    setActiveProtocolTab(newProtocolId);
  };

  const updateProtocol = (index: number, updates: any) => {
    setConfig(prev => ({
      ...prev,
      protocols: prev.protocols.map((p, i) => 
        i === index ? { ...p, ...updates } : p
      )
    }));
  };

  const removeProtocol = (index: number) => {
    setConfig(prev => ({
      ...prev,
      protocols: prev.protocols.filter((_, i) => i !== index)
    }));
  };

  const getDefaultProtocolSettings = (type: string, mode: 'client' | 'server') => {
    switch (type) {
      case 'modbus-tcp':
        return mode === 'server' ? {
          serverPort: 502,
          unitId: 1,
          registerMap: {
            holdingRegisters: { 
              start: 40001, 
              count: 10,
              variables: [
                { name: 'Temperature_SP', address: 40001, description: 'Temperature Setpoint' },
                { name: 'Pressure_SP', address: 40002, description: 'Pressure Setpoint' },
                { name: 'Speed_Control', address: 40003, description: 'Motor Speed Control' },
                { name: 'Flow_Rate_SP', address: 40004, description: 'Flow Rate Setpoint' },
                { name: 'Level_SP', address: 40005, description: 'Tank Level Setpoint' }
              ]
            },
            inputRegisters: { 
              start: 30001, 
              count: 10,
              variables: [
                { name: 'Temperature_PV', address: 30001, description: 'Temperature Process Value' },
                { name: 'Pressure_PV', address: 30002, description: 'Pressure Process Value' },
                { name: 'Speed_Feedback', address: 30003, description: 'Motor Speed Feedback' },
                { name: 'Flow_Rate_PV', address: 30004, description: 'Flow Rate Process Value' },
                { name: 'Level_PV', address: 30005, description: 'Tank Level Process Value' }
              ]
            },
            coils: {
              start: 1,
              count: 10,
              variables: [
                { name: 'Motor_Start', address: 1, description: 'Motor Start Command' },
                { name: 'Pump_Enable', address: 2, description: 'Pump Enable' },
                { name: 'Valve_Open', address: 3, description: 'Main Valve Open' },
                { name: 'Alarm_Reset', address: 4, description: 'Alarm Reset' },
                { name: 'Emergency_Stop', address: 5, description: 'Emergency Stop' }
              ]
            },
            discreteInputs: {
              start: 10001,
              count: 10,
              variables: [
                { name: 'Motor_Running', address: 10001, description: 'Motor Running Status' },
                { name: 'High_Temp_Alarm', address: 10002, description: 'High Temperature Alarm' },
                { name: 'Low_Pressure_Alarm', address: 10003, description: 'Low Pressure Alarm' },
                { name: 'Emergency_Stop_Status', address: 10004, description: 'Emergency Stop Active' },
                { name: 'System_Ready', address: 10005, description: 'System Ready Status' }
              ]
            }
          }
        } : {
          devices: [{
            name: 'Device1',
            ip: '192.168.1.100',
            port: 502,
            unitId: 1
          }]
        };
      case 'opcua':
        return mode === 'server' ? {
          serverPort: 4840,
          namespace: 'urn:gateway:opcua',
          variables: [
            { name: 'Temperature', nodeId: 'ns=2;s=Temperature', dataType: 'Double', description: 'Process Temperature' },
            { name: 'Pressure', nodeId: 'ns=2;s=Pressure', dataType: 'Double', description: 'System Pressure' },
            { name: 'Running', nodeId: 'ns=2;s=Running', dataType: 'Boolean', description: 'System Running State' },
            { name: 'Speed', nodeId: 'ns=2;s=Speed', dataType: 'Int32', description: 'Motor Speed RPM' },
            { name: 'SetPoint', nodeId: 'ns=2;s=SetPoint', dataType: 'Double', description: 'Control Setpoint' }
          ]
        } : {
          endpoint: 'opc.tcp://192.168.1.100:4840'
        };
      case 'mqtt':
        return {
          broker: 'mqtt://localhost:1883',
          topics: [
            { name: 'Temperature', topic: 'sensor/temperature', dataType: 'double', description: 'Temperature sensor data' },
            { name: 'Humidity', topic: 'sensor/humidity', dataType: 'double', description: 'Humidity sensor data' },
            { name: 'Status', topic: 'device/status', dataType: 'string', description: 'Device status messages' },
            { name: 'Control', topic: 'control/setpoint', dataType: 'double', description: 'Control setpoint commands' }
          ],
          qos: 1
        };
      case 'profinet':
        return {
          modules: [
            { name: 'DigitalInput_1', type: 'input', channels: 8, description: 'Digital Input Module 1' },
            { name: 'DigitalOutput_1', type: 'output', channels: 8, description: 'Digital Output Module 1' },
            { name: 'AnalogInput_1', type: 'analog_input', channels: 4, description: 'Analog Input Module 1' },
            { name: 'AnalogOutput_1', type: 'analog_output', channels: 2, description: 'Analog Output Module 1' }
          ]
        };
      default:
        return {};
    }
  };

  const generateGateway = async () => {
    setIsGenerating(true);
    try {
      const files = await generateServerFiles(config);
      
      // Create and download the ZIP file
      const blob = new Blob([files.zipBuffer], { type: 'application/zip' });
      const url = URL.createObjectURL(blob);
      
      const link = document.createElement('a');
      link.href = url;
      link.download = `${config.name.toLowerCase().replace(/[^a-z0-9]/g, '-')}-gateway.zip`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      
      // Cleanup URL
      URL.revokeObjectURL(url);
      
    } catch (error) {
      console.error('Generation error:', error);
      alert('Failed to generate gateway. Please check the configuration.');
    } finally {
      setIsGenerating(false);
    }
  };

  const getProtocolVariables = (protocol: ProtocolConfig) => {
    const settings = protocol.settings || {};
    
    switch (protocol.type) {
      case 'modbus-tcp':
      case 'modbus-rtu':
        const variables = [];
        
        // Add holding registers
        if (settings.registerMap?.holdingRegisters?.variables) {
          variables.push(...settings.registerMap.holdingRegisters.variables.map((v: any) => ({
            name: v.name,
            dataType: 'int16',
            writable: true,
            description: v.description,
            address: v.address
          })));
        }
        
        // Add input registers
        if (settings.registerMap?.inputRegisters?.variables) {
          variables.push(...settings.registerMap.inputRegisters.variables.map((v: any) => ({
            name: v.name,
            dataType: 'int16',
            writable: false,
            description: v.description,
            address: v.address
          })));
        }
        
        // Add coils
        if (settings.registerMap?.coils?.variables) {
          variables.push(...settings.registerMap.coils.variables.map((v: any) => ({
            name: v.name,
            dataType: 'boolean',
            writable: true,
            description: v.description,
            address: v.address
          })));
        }
        
        // Add discrete inputs
        if (settings.registerMap?.discreteInputs?.variables) {
          variables.push(...settings.registerMap.discreteInputs.variables.map((v: any) => ({
            name: v.name,
            dataType: 'boolean',
            writable: false,
            description: v.description,
            address: v.address
          })));
        }
        
        return variables;
        
      case 'opcua':
        if (settings.variables) {
          return settings.variables.map((v: any) => ({
            name: v.name,
            dataType: v.dataType.toLowerCase(),
            writable: true,
            description: v.description,
            nodeId: v.nodeId
          }));
        }
        return [
          { name: 'Temperature', dataType: 'double', writable: true, description: 'Temperature sensor' },
          { name: 'Pressure', dataType: 'double', writable: true, description: 'Pressure sensor' },
          { name: 'Running', dataType: 'boolean', writable: true, description: 'Running status' },
          { name: 'Speed', dataType: 'int32', writable: true, description: 'Motor speed' },
          { name: 'SetPoint', dataType: 'double', writable: true, description: 'Control setpoint' }
        ];
        
      case 'mqtt':
        if (settings.topics && Array.isArray(settings.topics)) {
          return settings.topics.map((t: any) => ({
            name: typeof t === 'string' ? t : t.name || t.topic,
            dataType: t.dataType || 'string',
            writable: true,
            description: t.description || `MQTT topic: ${t.topic || t.name}`,
            topic: t.topic || t.name
          }));
        }
        return [
          { name: 'sensor/temperature', dataType: 'double', writable: true, description: 'Temperature topic' },
          { name: 'sensor/humidity', dataType: 'double', writable: false, description: 'Humidity topic' },
          { name: 'device/status', dataType: 'string', writable: true, description: 'Device status' },
          { name: 'alarm/critical', dataType: 'boolean', writable: true, description: 'Critical alarm' },
          { name: 'control/setpoint', dataType: 'double', writable: true, description: 'Control setpoint' }
        ];
        
      case 'profinet':
        if (settings.modules) {
          const variables = [];
          settings.modules.forEach((module: any) => {
            for (let i = 1; i <= (module.channels || 1); i++) {
              variables.push({
                name: `${module.name}/Channel_${i}`,
                dataType: module.type.includes('analog') ? 'int16' : 'boolean',
                writable: module.type.includes('output'),
                description: `${module.description} - Channel ${i}`,
                module: module.name
              });
            }
          });
          return variables;
        }
        return [
          { name: 'InputModule_1/Channel_1', dataType: 'boolean', writable: false, description: 'Digital Input 1' },
          { name: 'OutputModule_1/Channel_1', dataType: 'boolean', writable: true, description: 'Digital Output 1' },
          { name: 'AnalogInput_1/Value', dataType: 'int16', writable: false, description: 'Analog Input (0-4095)' },
          { name: 'AnalogOutput_1/Value', dataType: 'int16', writable: true, description: 'Analog Output (0-4095)' }
        ];
        
      default:
        return [
          { name: 'Variable_1', dataType: 'unknown', writable: true, description: 'Generic variable' }
        ];
    }
  };

  return (
    <div className="gateway-builder">
      <div className="config-panel">
        <h2>Gateway Configuration</h2>
        
        {/* Basic Settings */}
        <div className="config-section">
          <h3>Basic Settings</h3>
          <div className="form-group">
            <label>Gateway Name:</label>
            <input
              type="text"
              value={config.name}
              onChange={(e) => updateConfig('name', e.target.value)}
              placeholder="Industrial Gateway"
            />
          </div>
          <div className="form-group">
            <label>Version:</label>
            <input
              type="text"
              value={config.version}
              onChange={(e) => updateConfig('version', e.target.value)}
              placeholder="1.0.0"
            />
          </div>
          <div className="form-group">
            <label>Description:</label>
            <textarea
              value={config.description}
              onChange={(e) => updateConfig('description', e.target.value)}
              placeholder="Industrial Protocol Gateway Server"
            />
          </div>
        </div>

        {/* Server Settings */}
        <div className="config-section">
          <h3>Server Settings</h3>
          <div className="form-row">
            <div className="form-group">
              <label>Host:</label>
              <input
                type="text"
                value={config.server.host}
                onChange={(e) => updateConfig('server', { ...config.server, host: e.target.value })}
                placeholder="0.0.0.0"
              />
            </div>
            <div className="form-group">
              <label>Port:</label>
              <input
                type="number"
                value={config.server.port}
                onChange={(e) => updateConfig('server', { ...config.server, port: parseInt(e.target.value) })}
                placeholder="8080"
              />
            </div>
          </div>
        </div>

        {/* Protocols */}
        <div className="config-section">
          <h3>Protocols</h3>
          {config.protocols.map((protocol, index) => (
            <div key={protocol.id} className="protocol-card">
              <div className="protocol-header">
                <div className="form-row">
                  <div className="form-group">
                    <label>Name:</label>
                    <input
                      type="text"
                      value={protocol.name}
                      onChange={(e) => updateProtocol(index, { name: e.target.value })}
                    />
                  </div>
                  <div className="form-group">
                    <label>Type:</label>
                    <select
                      value={protocol.type}
                      onChange={(e) => {
                        const newType = e.target.value;
                        updateProtocol(index, {
                          type: newType,
                          settings: getDefaultProtocolSettings(newType, protocol.mode)
                        });
                      }}
                    >
                      {protocolTypes.map(type => (
                        <option key={type.value} value={type.value}>
                          {type.label}
                        </option>
                      ))}
                    </select>
                  </div>
                  <div className="form-group">
                    <label>Mode:</label>
                    <select
                      value={protocol.mode}
                      onChange={(e) => {
                        const newMode = e.target.value as 'client' | 'server';
                        updateProtocol(index, {
                          mode: newMode,
                          settings: getDefaultProtocolSettings(protocol.type, newMode)
                        });
                      }}
                    >
                      <option value="server">Server</option>
                      <option value="client">Client</option>
                    </select>
                  </div>
                  <div className="form-group">
                    <label>
                      <input
                        type="checkbox"
                        checked={protocol.enabled}
                        onChange={(e) => updateProtocol(index, { enabled: e.target.checked })}
                      />
                      Enabled
                    </label>
                  </div>
                  <button
                    type="button"
                    onClick={() => removeProtocol(index)}
                    className="btn-remove"
                  >
                    Remove
                  </button>
                </div>
              </div>
              
              {/* Protocol-specific settings */}
              <div className="protocol-settings">
                <h4>Variable Configuration</h4>
                
                {protocol.type === 'modbus-tcp' || protocol.type === 'modbus-rtu' ? (
                  <div className="modbus-config">
                    <div className="form-row">
                      <div className="form-group">
                        <label>Server Port:</label>
                        <input
                          type="number"
                          value={protocol.settings?.serverPort || 502}
                          onChange={(e) => updateProtocol(index, {
                            settings: {
                              ...protocol.settings,
                              serverPort: parseInt(e.target.value)
                            }
                          })}
                        />
                      </div>
                      <div className="form-group">
                        <label>Unit ID:</label>
                        <input
                          type="number"
                          value={protocol.settings?.unitId || 1}
                          onChange={(e) => updateProtocol(index, {
                            settings: {
                              ...protocol.settings,
                              unitId: parseInt(e.target.value)
                            }
                          })}
                        />
                      </div>
                    </div>

                    {/* Holding Registers */}
                    <div className="register-section">
                      <h5>Holding Registers (Read/Write)</h5>
                      <div className="form-row">
                        <div className="form-group">
                          <label>Start Address:</label>
                          <input
                            type="number"
                            value={protocol.settings?.registerMap?.holdingRegisters?.start || 40001}
                            onChange={(e) => {
                              const newStart = parseInt(e.target.value);
                              const variables = protocol.settings?.registerMap?.holdingRegisters?.variables || [];
                              const updatedVariables = variables.map((v: any, idx: number) => ({
                                ...v,
                                address: newStart + idx
                              }));
                              updateProtocol(index, {
                                settings: {
                                  ...protocol.settings,
                                  registerMap: {
                                    ...protocol.settings?.registerMap,
                                    holdingRegisters: {
                                      ...protocol.settings?.registerMap?.holdingRegisters,
                                      start: newStart,
                                      variables: updatedVariables
                                    }
                                  }
                                }
                              });
                            }}
                          />
                        </div>
                        <div className="form-group">
                          <label>Count:</label>
                          <input
                            type="number"
                            value={protocol.settings?.registerMap?.holdingRegisters?.count || 10}
                            onChange={(e) => {
                              const newCount = parseInt(e.target.value);
                              const start = protocol.settings?.registerMap?.holdingRegisters?.start || 40001;
                              const currentVariables = protocol.settings?.registerMap?.holdingRegisters?.variables || [];
                              let newVariables = [...currentVariables];
                              
                              if (newCount > currentVariables.length) {
                                // Add new variables
                                for (let i = currentVariables.length; i < newCount; i++) {
                                  newVariables.push({
                                    name: `HR_Variable_${i + 1}`,
                                    address: start + i,
                                    description: `Holding Register ${start + i}`
                                  });
                                }
                              } else {
                                // Remove excess variables
                                newVariables = newVariables.slice(0, newCount);
                              }
                              
                              updateProtocol(index, {
                                settings: {
                                  ...protocol.settings,
                                  registerMap: {
                                    ...protocol.settings?.registerMap,
                                    holdingRegisters: {
                                      start,
                                      count: newCount,
                                      variables: newVariables
                                    }
                                  }
                                }
                              });
                            }}
                          />
                        </div>
                      </div>
                      
                      <div className="variable-list">
                        {(protocol.settings?.registerMap?.holdingRegisters?.variables || []).map((variable: any, varIdx: number) => (
                          <div key={varIdx} className="variable-editor">
                            <div className="form-row">
                              <div className="form-group">
                                <label>Name:</label>
                                <input
                                  type="text"
                                  value={variable.name}
                                  onChange={(e) => {
                                    const updatedVariables = [...(protocol.settings?.registerMap?.holdingRegisters?.variables || [])];
                                    updatedVariables[varIdx] = { ...variable, name: e.target.value };
                                    updateProtocol(index, {
                                      settings: {
                                        ...protocol.settings,
                                        registerMap: {
                                          ...protocol.settings?.registerMap,
                                          holdingRegisters: {
                                            ...protocol.settings?.registerMap?.holdingRegisters,
                                            variables: updatedVariables
                                          }
                                        }
                                      }
                                    });
                                  }}
                                />
                              </div>
                              <div className="form-group">
                                <label>Address:</label>
                                <input
                                  type="number"
                                  value={variable.address}
                                  readOnly
                                  className="readonly"
                                />
                              </div>
                              <div className="form-group">
                                <label>Description:</label>
                                <input
                                  type="text"
                                  value={variable.description}
                                  onChange={(e) => {
                                    const updatedVariables = [...(protocol.settings?.registerMap?.holdingRegisters?.variables || [])];
                                    updatedVariables[varIdx] = { ...variable, description: e.target.value };
                                    updateProtocol(index, {
                                      settings: {
                                        ...protocol.settings,
                                        registerMap: {
                                          ...protocol.settings?.registerMap,
                                          holdingRegisters: {
                                            ...protocol.settings?.registerMap?.holdingRegisters,
                                            variables: updatedVariables
                                          }
                                        }
                                      }
                                    });
                                  }}
                                />
                              </div>
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>

                    {/* Input Registers */}
                    <div className="register-section">
                      <h5>Input Registers (Read Only)</h5>
                      <div className="form-row">
                        <div className="form-group">
                          <label>Start Address:</label>
                          <input
                            type="number"
                            value={protocol.settings?.registerMap?.inputRegisters?.start || 30001}
                            onChange={(e) => {
                              const newStart = parseInt(e.target.value);
                              const variables = protocol.settings?.registerMap?.inputRegisters?.variables || [];
                              const updatedVariables = variables.map((v: any, idx: number) => ({
                                ...v,
                                address: newStart + idx
                              }));
                              updateProtocol(index, {
                                settings: {
                                  ...protocol.settings,
                                  registerMap: {
                                    ...protocol.settings?.registerMap,
                                    inputRegisters: {
                                      ...protocol.settings?.registerMap?.inputRegisters,
                                      start: newStart,
                                      variables: updatedVariables
                                    }
                                  }
                                }
                              });
                            }}
                          />
                        </div>
                        <div className="form-group">
                          <label>Count:</label>
                          <input
                            type="number"
                            value={protocol.settings?.registerMap?.inputRegisters?.count || 10}
                            onChange={(e) => {
                              const newCount = parseInt(e.target.value);
                              const start = protocol.settings?.registerMap?.inputRegisters?.start || 30001;
                              const currentVariables = protocol.settings?.registerMap?.inputRegisters?.variables || [];
                              let newVariables = [...currentVariables];
                              
                              if (newCount > currentVariables.length) {
                                for (let i = currentVariables.length; i < newCount; i++) {
                                  newVariables.push({
                                    name: `IR_Variable_${i + 1}`,
                                    address: start + i,
                                    description: `Input Register ${start + i}`
                                  });
                                }
                              } else {
                                newVariables = newVariables.slice(0, newCount);
                              }
                              
                              updateProtocol(index, {
                                settings: {
                                  ...protocol.settings,
                                  registerMap: {
                                    ...protocol.settings?.registerMap,
                                    inputRegisters: {
                                      start,
                                      count: newCount,
                                      variables: newVariables
                                    }
                                  }
                                }
                              });
                            }}
                          />
                        </div>
                      </div>
                      
                      <div className="variable-list">
                        {(protocol.settings?.registerMap?.inputRegisters?.variables || []).map((variable: any, varIdx: number) => (
                          <div key={varIdx} className="variable-editor">
                            <div className="form-row">
                              <div className="form-group">
                                <label>Name:</label>
                                <input
                                  type="text"
                                  value={variable.name}
                                  onChange={(e) => {
                                    const updatedVariables = [...(protocol.settings?.registerMap?.inputRegisters?.variables || [])];
                                    updatedVariables[varIdx] = { ...variable, name: e.target.value };
                                    updateProtocol(index, {
                                      settings: {
                                        ...protocol.settings,
                                        registerMap: {
                                          ...protocol.settings?.registerMap,
                                          inputRegisters: {
                                            ...protocol.settings?.registerMap?.inputRegisters,
                                            variables: updatedVariables
                                          }
                                        }
                                      }
                                    });
                                  }}
                                />
                              </div>
                              <div className="form-group">
                                <label>Address:</label>
                                <input
                                  type="number"
                                  value={variable.address}
                                  readOnly
                                  className="readonly"
                                />
                              </div>
                              <div className="form-group">
                                <label>Description:</label>
                                <input
                                  type="text"
                                  value={variable.description}
                                  onChange={(e) => {
                                    const updatedVariables = [...(protocol.settings?.registerMap?.inputRegisters?.variables || [])];
                                    updatedVariables[varIdx] = { ...variable, description: e.target.value };
                                    updateProtocol(index, {
                                      settings: {
                                        ...protocol.settings,
                                        registerMap: {
                                          ...protocol.settings?.registerMap,
                                          inputRegisters: {
                                            ...protocol.settings?.registerMap?.inputRegisters,
                                            variables: updatedVariables
                                          }
                                        }
                                      }
                                    });
                                  }}
                                />
                              </div>
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>
                  </div>
                ) : protocol.type === 'opcua' ? (
                  <div className="opcua-config">
                    <div className="form-row">
                      <div className="form-group">
                        <label>Server Port:</label>
                        <input
                          type="number"
                          value={protocol.settings?.serverPort || 4840}
                          onChange={(e) => updateProtocol(index, {
                            settings: {
                              ...protocol.settings,
                              serverPort: parseInt(e.target.value)
                            }
                          })}
                        />
                      </div>
                      <div className="form-group">
                        <label>Namespace:</label>
                        <input
                          type="text"
                          value={protocol.settings?.namespace || 'urn:gateway:opcua'}
                          onChange={(e) => updateProtocol(index, {
                            settings: {
                              ...protocol.settings,
                              namespace: e.target.value
                            }
                          })}
                        />
                      </div>
                    </div>
                    
                    <div className="variable-section">
                      <h5>OPC UA Variables</h5>
                      <div className="variable-list">
                        {(protocol.settings?.variables || []).map((variable: any, varIdx: number) => (
                          <div key={varIdx} className="variable-editor">
                            <div className="form-row">
                              <div className="form-group">
                                <label>Name:</label>
                                <input
                                  type="text"
                                  value={variable.name}
                                  onChange={(e) => {
                                    const updatedVariables = [...(protocol.settings?.variables || [])];
                                    updatedVariables[varIdx] = { ...variable, name: e.target.value, nodeId: `ns=2;s=${e.target.value}` };
                                    updateProtocol(index, {
                                      settings: {
                                        ...protocol.settings,
                                        variables: updatedVariables
                                      }
                                    });
                                  }}
                                />
                              </div>
                              <div className="form-group">
                                <label>Data Type:</label>
                                <select
                                  value={variable.dataType}
                                  onChange={(e) => {
                                    const updatedVariables = [...(protocol.settings?.variables || [])];
                                    updatedVariables[varIdx] = { ...variable, dataType: e.target.value };
                                    updateProtocol(index, {
                                      settings: {
                                        ...protocol.settings,
                                        variables: updatedVariables
                                      }
                                    });
                                  }}
                                >
                                  <option value="Boolean">Boolean</option>
                                  <option value="Int32">Int32</option>
                                  <option value="Double">Double</option>
                                  <option value="String">String</option>
                                </select>
                              </div>
                              <div className="form-group">
                                <label>Description:</label>
                                <input
                                  type="text"
                                  value={variable.description}
                                  onChange={(e) => {
                                    const updatedVariables = [...(protocol.settings?.variables || [])];
                                    updatedVariables[varIdx] = { ...variable, description: e.target.value };
                                    updateProtocol(index, {
                                      settings: {
                                        ...protocol.settings,
                                        variables: updatedVariables
                                      }
                                    });
                                  }}
                                />
                              </div>
                              <button
                                type="button"
                                onClick={() => {
                                  const updatedVariables = [...(protocol.settings?.variables || [])];
                                  updatedVariables.splice(varIdx, 1);
                                  updateProtocol(index, {
                                    settings: {
                                      ...protocol.settings,
                                      variables: updatedVariables
                                    }
                                  });
                                }}
                                className="btn-remove-var"
                              >
                                âś•
                              </button>
                            </div>
                          </div>
                        ))}
                        <button
                          type="button"
                          onClick={() => {
                            const newVariable = {
                              name: `Variable_${(protocol.settings?.variables?.length || 0) + 1}`,
                              nodeId: `ns=2;s=Variable_${(protocol.settings?.variables?.length || 0) + 1}`,
                              dataType: 'Double',
                              description: 'New OPC UA Variable'
                            };
                            updateProtocol(index, {
                              settings: {
                                ...protocol.settings,
                                variables: [...(protocol.settings?.variables || []), newVariable]
                              }
                            });
                          }}
                          className="btn-add-var"
                        >
                          Add Variable
                        </button>
                      </div>
                    </div>
                  </div>
                ) : (
                  <div className="generic-settings">
                    <h5>Settings</h5>
                    <pre>{JSON.stringify(protocol.settings, null, 2)}</pre>
                  </div>
                )}
              </div>
            </div>
          ))}
          
          <button type="button" onClick={addProtocol} className="btn-add">
            Add Protocol
          </button>
        </div>

        {/* Generate Button */}
        <div className="config-section">
          <button
            type="button"
            onClick={generateGateway}
            disabled={isGenerating}
            className="btn-generate"
          >
            {isGenerating ? 'Generating...' : 'Generate EXE Gateway'}
          </button>
        </div>

        {/* REST API Documentation */}
        <div className="config-section">
          <h3>đź”Ś Generated REST API Documentation</h3>
          <p>Your generated gateway will expose these REST API endpoints for variable access:</p>
          
          <div className="api-section">
            <h4>đź“ˇ Base URL</h4>
            <div className="api-endpoint">
              <code>http://{config.server.host}:{config.server.port}</code>
              <span className="description">Gateway server base URL</span>
            </div>
          </div>

          <div className="api-section">
            <h4>đź”Ť Discovery & Health Endpoints</h4>
            <div className="api-endpoint">
              <span className="method get">GET</span>
              <code>/health</code>
              <span className="description">Server health, uptime, and protocol status</span>
            </div>
            <div className="api-endpoint">
              <span className="method get">GET</span>
              <code>/api/protocols</code>
              <span className="description">List all protocols and their available variables</span>
            </div>
          </div>

          <div className="api-section">
            <h4>đź“– Variable Read Operations</h4>
            <div className="api-endpoint">
              <span className="method get">GET</span>
              <code>/api/&#123;protocolId&#125;/variables/&#123;variableName&#125;</code>
              <span className="description">Read single variable with metadata</span>
            </div>
            <div className="api-endpoint">
              <span className="method post">POST</span>
              <code>/api/&#123;protocolId&#125;/variables/read</code>
              <span className="description">Bulk read multiple variables</span>
            </div>
          </div>

          <div className="api-section">
            <h4>âśŤď¸Ź Variable Write Operations</h4>
            <div className="api-endpoint">
              <span className="method post">POST</span>
              <code>/api/&#123;protocolId&#125;/variables/&#123;variableName&#125;</code>
              <span className="description">Write single variable value</span>
            </div>
            <div className="api-endpoint">
              <span className="method post">POST</span>
              <code>/api/&#123;protocolId&#125;/variables/write</code>
              <span className="description">Bulk write multiple variables</span>
            </div>
          </div>

          {config.protocols.length > 0 && (
            <div className="api-section">
              <h4>đźŹ·ď¸Ź Available Variables by Protocol</h4>
              {config.protocols.map((protocol, index) => (
                <div key={index} className="protocol-variables">
                  <h5>đź“Ś {protocol.name} ({protocol.type.toUpperCase()}) - ID: {protocol.id}</h5>
                  <div className="variable-examples">
                    {getProtocolVariables(protocol).map((variable, idx) => (
                      <div key={idx} className="variable-item">
                        <code className="variable-name">{variable.name}</code>
                        <span className="variable-type">{variable.dataType}</span>
                        <span className={`variable-access ${variable.writable ? 'rw' : 'ro'}`}>
                          {variable.writable ? 'R/W' : 'R/O'}
                        </span>
                        <span className="variable-description">{variable.description}</span>
                      </div>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          )}

          <div className="api-section">
            <h4>đź’ˇ Example Requests</h4>
            <div className="example-requests">
              <div className="example">
                <h5>đź”Ť Get Server Health:</h5>
                <pre><code>curl http://{config.server.host}:{config.server.port}/health</code></pre>
              </div>
              <div className="example">
                <h5>đź“‹ List All Protocols:</h5>
                <pre><code>curl http://{config.server.host}:{config.server.port}/api/protocols</code></pre>
              </div>
              {config.protocols.length > 0 && (
                <>
                  <div className="example">
                    <h5>đź“– Read Variable:</h5>
                    <pre><code>curl http://{config.server.host}:{config.server.port}/api/{config.protocols[0].id}/variables/{getProtocolVariables(config.protocols[0])[0]?.name}</code></pre>
                  </div>
                  <div className="example">
                    <h5>âśŤď¸Ź Write Variable:</h5>
                    <pre><code>curl -X POST http://{config.server.host}:{config.server.port}/api/{config.protocols[0].id}/variables/{getProtocolVariables(config.protocols[0]).find(v => v.writable)?.name} \{'\n'}  -H "Content-Type: application/json" \{'\n'}  -d '&#123;"value": {getProtocolVariables(config.protocols[0]).find(v => v.writable)?.dataType === 'boolean' ? 'true' : getProtocolVariables(config.protocols[0]).find(v => v.writable)?.dataType === 'string' ? '"hello"' : '1500'}&#125;'</code></pre>
                  </div>
                  <div className="example">
                    <h5>đź“š Bulk Read Variables:</h5>
                    <pre><code>curl -X POST http://{config.server.host}:{config.server.port}/api/{config.protocols[0].id}/variables/read \{'\n'}  -H "Content-Type: application/json" \{'\n'}  -d '&#123;"variables": ["{getProtocolVariables(config.protocols[0])[0]?.name}", "{getProtocolVariables(config.protocols[0])[1]?.name}"]&#125;'</code></pre>
                  </div>
                </>
              )}
            </div>
          </div>

          <div className="api-section">
            <h4>đź›ˇď¸Ź Response Format</h4>
            <div className="example-requests">
              <div className="example">
                <h5>âś… Successful Read Response:</h5>
                <pre><code>{`{
  "protocol": "modbus-1",
  "variable": "HR_40001", 
  "device": "default",
  "value": 1500,
  "dataType": "int16",
  "quality": "good",
  "timestamp": "2026-02-05T10:30:00.000Z"
}`}</code></pre>
              </div>
              <div className="example">
                <h5>âťŚ Error Response:</h5>
                <pre><code>{`{
  "error": "Variable 'HR_99999' not found",
  "protocol": "modbus-1",
  "timestamp": "2026-02-05T10:30:00.000Z"
}`}</code></pre>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default GatewayBuilder;
